"use client";

import { signIn } from "next-auth/react";
import Image from "next/image";

export default function SignIn() {
    return (
        <div className="flex min-h-screen items-center justify-center bg-stone-950 px-8">
            <div className="w-full max-w-md bg-stone-900 p-12 shadow-2xl border border-stone-800">
                <div className="mb-12 text-center">
                    <h1 className="text-3xl font-serif text-white tracking-widest mb-4 uppercase">CASA YOLOTL</h1>
                    <div className="h-px w-24 bg-brand-gold mx-auto mb-4"></div>
                    <p className="text-[10px] uppercase tracking-[0.4em] text-stone-500 font-bold">Terminal Administrativa</p>
                </div>

                <p className="text-xs text-stone-400 mb-12 text-center leading-relaxed italic">
                    "Representamos cultura con disciplina empresarial."
                </p>

                <button
                    onClick={() => signIn("google", { callbackUrl: "/dashboard" })}
                    className="w-full bg-white text-stone-900 py-4 text-[10px] font-bold uppercase tracking-[0.3em] hover:bg-stone-300 transition-all duration-500 flex items-center justify-center gap-4 shadow-xl group"
                >
                    <svg className="w-4 h-4" viewBox="0 0 24 24">
                        <path fill="currentColor" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                        <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                        <path fill="#FBBC05" d="M5.84 14.1c-.22-.66-.35-1.36-.35-2.1s.13-1.44.35-2.1V7.06H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.94l3.66-2.84z" />
                        <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.06l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                    </svg>
                    Acceder con Google
                </button>

                <div className="mt-12 text-center">
                    <p className="text-[9px] text-stone-600 uppercase tracking-widest leading-loose">
                        Acceso restringido. El sistema monitorea intentos de entrada no autorizados.
                    </p>
                </div>
            </div>
        </div>
    );
}
